@startuml
skinparam classAttributeIconSize 0

interface Account {
    applyMonthlyChange()
}

class CreditAccount {
    ...someAttribute
    --
    applyMonthlyInterest()
    applyMonthlyChange()
    ...someOtherMethod()
}

class DebitAccount {
    ...someAttribute
    --
    applyMonthlyInterest()
    deactivateIfUnderBalanced()
    applyMonthlyChange()
    ...someOtherMethod()
}

class PayrollAccount {
    ...someAttribute
    --
    applyMonthlyChange()
    ...someMethod()
}

note right of Bank : 
applyAllMonthlyChanges(){  
...   
for every account a in accounts{    
a.applyMonthlyChange     
}} 

Bank "1" *-- "*" Account : >
CreditAccount ..|> Account
DebitAccount ..|> Account
PayrollAccount .u.|> Account


@enduml
